request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?jplReqName ?tmtReqName ?rel WHERE {
  ?jplReq rdf:type vocab:tmt%20requirement .
  ?tmtReq rdf:type vocab:tmt%20requirement .

  ?jplReq vocab:NamedElement_name ?jplReqName .
  ?tmtReq vocab:NamedElement_name ?tmtReqName .

  FILTER(
    CONTAINS(LCASE(STR(?jplReqName)), LCASE("power")) ||
    CONTAINS(LCASE(STR(?jplReqName)), LCASE("limit"))
  )
  FILTER(
    CONTAINS(LCASE(STR(?tmtReqName)), LCASE("power")) ||
    CONTAINS(LCASE(STR(?tmtReqName)), LCASE("limit"))
  )

  {
    ?jplReq vocab:satisfy ?tmtReq .
    BIND("satisfy" AS ?rel)
  }
  UNION
  {
    ?jplReq vocab:verify ?tmtReq .
    BIND("verify" AS ?rel)
  }
  UNION
  {
    ?jplReq vocab:allocate ?tmtReq .
    BIND("allocate" AS ?rel)
  }
  UNION
  {
    ?jplReq vocab:dependency_client ?tmtReq .
    BIND("dependency_client" AS ?rel)
  }
  UNION
  {
    ?jplReq vocab:dependency_supplier ?tmtReq .
    BIND("dependency_supplier" AS ?rel)
  }

  FILTER(?jplReq != ?tmtReq)
}
LIMIT 25
